// ===============================
// GLOBALS
// ===============================
let inkCodes = [];
let currentOrderNumber = "LAM001";

// ===============================
// LOAD INK CODES JSON
// ===============================
fetch("inkcodes.json")
    .then(r => r.json())
    .then(data => {
        inkCodes = data;
        console.log("Ink codes loaded:", inkCodes.length);
    })
    .catch(err => console.error("Error loading inkcodes.json:", err));

// ===============================
// INITIALISE ORDER FORM
// ===============================
document.addEventListener("DOMContentLoaded", () => {
    autoFillDate();
    loadNextOrderNumber();

    document.getElementById("addItemRow").addEventListener("click", addItemRow);
    document.getElementById("clearItems").addEventListener("click", clearAllItems);
    document.getElementById("saveOrder").addEventListener("click", saveOrder);
});

// ===============================
// AUTO-FILL DATE
// ===============================
function autoFillDate() {
    const today = new Date().toISOString().split("T")[0];
    document.getElementById("orderDate").value = today;
}

// ===============================
// ORDER NUMBER HANDLING (LAM001)
// ===============================
function loadNextOrderNumber() {
    const saved = localStorage.getItem("lastOrderNumber");

    if (!saved) {
        currentOrderNumber = "LAM001";
    } else {
        const num = parseInt(saved.replace("LAM", ""));
        const next = num + 1;
        currentOrderNumber = "LAM" + String(next).padStart(3, "0");
    }

    document.getElementById("orderNumber").value = currentOrderNumber;
}

// ===============================
// ADD ITEM ROW
// ===============================
function addItemRow() {
    const tbody = document.getElementById("itemsBody");

    const row = document.createElement("tr");
    row.innerHTML = `
        <td>
            <select class="form-control item-type">
                <option value="Ink">Ink</option>
                <option value="Tape">Tape</option>
                <option value="Boxes">Boxes</option>
                <option value="Cores">Cores</option>
                <option value="Solvent">Solvent</option>
                <option value="Other">Other</option>
            </select>
        </td>

        <td>
            <select class="form-control item-code">
                <option value="">Select Ink Code</option>
            </select>
        </td>

        <td>
            <input type="text" class="form-control item-desc" readonly>
        </td>

        <td>
            <input type="number" class="form-control item-qty" min="1" value="1">
        </td>

        <td>
            <input type="date" class="form-control item-date">
        </td>

        <td>
            <button class="btn btn-danger remove-row">X</button>
        </td>
    `;

    tbody.appendChild(row);
    attachRowLogic(row);
}

// ===============================
// POPULATE INK DROPDOWN
// ===============================
function populateInkDropdown(selectElement) {
    selectElement.innerHTML = `<option value="">Select Ink Code</option>`;
    inkCodes.forEach(ink => {
        const opt = document.createElement("option");
        opt.value = ink.code;
        opt.textContent = ink.code;
        selectElement.appendChild(opt);
    });
}

// ===============================
// ATTACH LOGIC TO EACH ROW
// ===============================
function attachRowLogic(row) {
    const typeSelect = row.querySelector(".item-type");
    const codeSelect = row.querySelector(".item-code");
    const descInput = row.querySelector(".item-desc");
    const removeBtn = row.querySelector(".remove-row");

    // Default: Ink selected → populate dropdown
    populateInkDropdown(codeSelect);

    // When item type changes
    typeSelect.addEventListener("change", () => {
        if (typeSelect.value === "Ink") {
            codeSelect.disabled = false;
            descInput.readOnly = true;
            descInput.value = "";
            populateInkDropdown(codeSelect);
        } else {
            codeSelect.innerHTML = `<option value="">N/A</option>`;
            descInput.readOnly = false;
            descInput.value = "";
        }
    });

    // When ink code selected → auto-fill description
    codeSelect.addEventListener("change", () => {
        const selected = inkCodes.find(i => i.code === codeSelect.value);
        descInput.value = selected ? selected.name : "";
    });

    // Remove row
    removeBtn.addEventListener("click", () => {
        row.remove();
    });
}

// ===============================
// CLEAR ALL ITEMS
// ===============================
function clearAllItems() {
    document.getElementById("itemsBody").innerHTML = "";
}

// ===============================
// SAVE ORDER
// ===============================
function saveOrder() {
    const order = {
        number: document.getElementById("orderNumber").value,
        date: document.getElementById("orderDate").value,
        supplier: document.getElementById("supplier").value,
        status: document.getElementById("orderStatus").value,
        comments: document.getElementById("orderComments").value,
        items: []
    };

    document.querySelectorAll("#itemsBody tr").forEach(row => {
        order.items.push({
            type: row.querySelector(".item-type").value,
            code: row.querySelector(".item-code").value,
            desc: row.querySelector(".item-desc").value,
            qty: row.querySelector(".item-qty").value,
            expected: row.querySelector(".item-date").value
        });
    });

    // Save to localStorage
    let orders = JSON.parse(localStorage.getItem("orders") || "[]");
    orders.push(order);
    localStorage.setItem("orders", JSON.stringify(orders));

    // Update last order number
    localStorage.setItem("lastOrderNumber", order.number);

    alert("Order saved!");

    // Reset form
    clearAllItems();
    loadNextOrderNumber();
    autoFillDate();
}
